import{_ as e,c as t,o as i,a1 as a}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"Privacy Policy: Data Protection | OpenCodeDocs","description":"Learn about our data collection, usage, and protection practices. We prioritize your privacy and transparency in handling personal information.","frontmatter":{"title":"Privacy Policy: Data Protection | OpenCodeDocs","sidebarTitle":"Privacy Policy","subtitle":"Privacy Policy: Data Protection","description":"Learn about our data collection, usage, and protection practices. We prioritize your privacy and transparency in handling personal information."},"headers":[],"relativePath":"privacy.md","filePath":"privacy.md"}'),r={name:"privacy.md"};function n(s,o,l,c,u,g){return i(),t("div",null,[...o[0]||(o[0]=[a('<h1 id="privacy-policy" tabindex="-1">Privacy Policy <a class="header-anchor" href="#privacy-policy" aria-label="Permalink to &quot;Privacy Policy&quot;">​</a></h1><p>Last Updated: 2026-01-01</p><p>Thank you for using OpenCodeDocs. We attach great importance to your privacy and personal information protection. This Privacy Policy will help you understand how we collect, use, store, and protect your personal information.</p><h2 id="_1-information-we-collect" tabindex="-1">1. Information We Collect <a class="header-anchor" href="#_1-information-we-collect" aria-label="Permalink to &quot;1. Information We Collect&quot;">​</a></h2><p>When you use OpenCodeDocs services, we may collect the following types of information:</p><h3 id="account-information" tabindex="-1">Account Information <a class="header-anchor" href="#account-information" aria-label="Permalink to &quot;Account Information&quot;">​</a></h3><ul><li><strong>Email Address</strong>: Used for account registration, login verification, and important notifications</li><li><strong>Username</strong>: The display name you choose</li><li><strong>GitHub Account Information</strong>: If you choose to log in using GitHub, we will obtain your public information</li></ul><h3 id="usage-data" tabindex="-1">Usage Data <a class="header-anchor" href="#usage-data" aria-label="Permalink to &quot;Usage Data&quot;">​</a></h3><ul><li><strong>Browsing History</strong>: Tutorial pages you visit and time spent</li><li><strong>Interaction Behavior</strong>: Operations such as code copying, chapter jumping, etc.</li><li><strong>Search History</strong>: Search keywords you use within the site</li></ul><h3 id="device-information" tabindex="-1">Device Information <a class="header-anchor" href="#device-information" aria-label="Permalink to &quot;Device Information&quot;">​</a></h3><ul><li><strong>Browser Type</strong>: Chrome, Firefox, Safari, etc.</li><li><strong>Operating System</strong>: Windows, macOS, Linux, etc.</li><li><strong>IP Address</strong>: Used for security protection and regional optimization</li></ul><h2 id="_2-how-we-use-information" tabindex="-1">2. How We Use Information <a class="header-anchor" href="#_2-how-we-use-information" aria-label="Permalink to &quot;2. How We Use Information&quot;">​</a></h2><p>The information we collect will be used for the following purposes:</p><ul><li><strong>Providing Services</strong>: Ensuring you can access and use tutorial content normally</li><li><strong>Personalized Experience</strong>: Remembering your reading progress and preference settings</li><li><strong>Product Improvement</strong>: Analyzing usage patterns to optimize content and functions</li><li><strong>Security</strong>: Detecting abnormal behavior to prevent abuse</li><li><strong>Sending Notifications</strong>: Sending tutorial update reminders and important announcements (unsubscribe available)</li></ul><h2 id="_3-information-sharing-and-disclosure" tabindex="-1">3. Information Sharing and Disclosure <a class="header-anchor" href="#_3-information-sharing-and-disclosure" aria-label="Permalink to &quot;3. Information Sharing and Disclosure&quot;">​</a></h2><p>We will not sell your personal information. We may share it only under the following circumstances:</p><ul><li><strong>Third-Party Service Providers</strong>: Such as Vercel (hosting), Plausible (analytics), who can only access information necessary to perform their duties</li><li><strong>Legal Requirements</strong>: Disclosing in accordance with laws, regulations, or government requirements</li><li><strong>Rights Protection</strong>: Necessary circumstances to protect the rights and interests of OpenCodeDocs and users</li></ul><h2 id="_4-data-storage-and-security" tabindex="-1">4. Data Storage and Security <a class="header-anchor" href="#_4-data-storage-and-security" aria-label="Permalink to &quot;4. Data Storage and Security&quot;">​</a></h2><ul><li><strong>Storage Location</strong>: Data is stored on secure servers located in the United States and the Asia-Pacific region</li><li><strong>Encryption Measures</strong>: TLS/SSL encryption is used for data transmission, and AES-256 encryption is used for sensitive data storage</li><li><strong>Access Control</strong>: Strict restriction of internal personnel&#39;s access to data</li><li><strong>Retention Period</strong>: After account cancellation, personal data will be deleted within 30 days</li></ul><h2 id="_5-your-rights" tabindex="-1">5. Your Rights <a class="header-anchor" href="#_5-your-rights" aria-label="Permalink to &quot;5. Your Rights&quot;">​</a></h2><p>According to the Personal Information Protection Law and GDPR, you have the following rights:</p><ul><li><strong>Right of Access</strong>: You have the right to view the personal information we hold about you</li><li><strong>Right to Rectification</strong>: You have the right to request correction of inaccurate personal information</li><li><strong>Right to Erasure</strong>: You have the right to request deletion of your personal information</li><li><strong>Right to Data Portability</strong>: You have the right to export your data in a common format</li><li><strong>Withdraw Consent</strong>: You have the right to withdraw your previously given consent at any time</li></ul><p>To exercise the above rights, please contact us via the contact information below.</p><h2 id="_6-cookie-policy" tabindex="-1">6. Cookie Policy <a class="header-anchor" href="#_6-cookie-policy" aria-label="Permalink to &quot;6. Cookie Policy&quot;">​</a></h2><p>We use the following types of Cookies:</p><ul><li><strong>Essential Cookies</strong>: Maintaining login status, remembering language preferences</li><li><strong>Analytics Cookies</strong>: Statistics on visits and usage patterns (using privacy-friendly Plausible)</li><li><strong>Advertising Cookies</strong>: <ul><li>Third party vendors, including Google, use cookies to serve ads based on a user&#39;s prior visits to your website or other websites.</li><li>Google&#39;s use of advertising cookies enables it and its partners to serve ads to your users based on their visit to your sites and/or other sites on the Internet.</li><li>Users may opt out of personalized advertising by visiting <a href="https://www.google.com/settings/ads" target="_blank" rel="noreferrer">Ads Settings</a>. (Alternatively, you can direct users to opt out of a third-party vendor&#39;s use of cookies for personalized advertising by visiting <a href="http://www.aboutads.info/choices/" target="_blank" rel="noreferrer">www.aboutads.info</a>.)</li></ul></li></ul><p>You can manage Cookies through your browser settings. Disabling essential Cookies may affect the normal use of some functions.</p><h2 id="_7-contact-us" tabindex="-1">7. Contact Us <a class="header-anchor" href="#_7-contact-us" aria-label="Permalink to &quot;7. Contact Us&quot;">​</a></h2><p>If you have any questions about this Privacy Policy or need to exercise your data rights, please contact:</p><ul><li><strong>Email</strong>: <a href="mailto:vbgatecom@gmail.com" target="_blank" rel="noreferrer">vbgatecom@gmail.com</a></li><li><strong>Response Time</strong>: We will reply to your request within 15 working days</li></ul>',30)])])}const p=e(r,[["render",n]]);export{h as __pageData,p as default};
